const input = $json || {};
const zalo_user_id = String(input.zalo_user_id || '').trim();
const zalo_msg_id = String(input.zalo_msg_id || '').trim();
const parsedInvoice = input.parsed_invoice || input.ParsedInvoice || null;
const mapped_so_far = Array.isArray(input.mapped_so_far) ? input.mapped_so_far : [];
const unmapped_items = Array.isArray(input.unmapped_items)
  ? input.unmapped_items
  : (parsedInvoice && Array.isArray(parsedInvoice.items) ? parsedInvoice.items : []);

if (!zalo_user_id || !zalo_msg_id) throw new Error('zalo_user_id and zalo_msg_id are required');
if (!unmapped_items.length) {
  return [{ json: { status: 'all_mapped', mapped_so_far, parsed_invoice: parsedInvoice } }];
}

const [pending_item, ...remaining_items] = unmapped_items;
const supplier_code = String(parsedInvoice?.supplier_code || input.supplier_code || 'UNKNOWN_SUPPLIER');

return [{ json: {
  zalo_user_id,
  zalo_msg_id,
  supplier_code,
  parsed_invoice: parsedInvoice,
  mapped_so_far,
  pending_item,
  remaining_items,
  started_at: Date.now()
}}];

