const ctx = $('Validate + Pick Pending Item').item.json;
const exactRows = $('Tier2 Exact Barcode Match').all().map(i => i.json);
const fuzzyRows = $('Tier2 Fuzzy Name Match').all().map(i => i.json);
const global_match = exactRows[0] || fuzzyRows[0] || null;

return [{ json: { ...ctx, global_match, tier2_found: !!global_match } }];

const gm = $json.global_match;
const msg = {
  recipient: { user_id: $json.zalo_user_id },
  message: {
    text: `📋 Bill ghi: "${$json.pending_item.item_name}"

🤖 Em gợi ý: ${gm.standard_name} (${gm.supplier_unit || '?'} -> ${gm.pos_unit || '?'}, rate=${gm.default_conversion_rate || 1})

Xác nhận giúp em nhé:`
  },
  buttons: [
    { title: '✅ Đúng rồi', payload: `GLOBAL_CONFIRM|${$json.zalo_user_id}` },
    { title: '❌ Không phải', payload: `GLOBAL_REJECT|${$json.zalo_user_id}` }
  ]
};
return [{ json: { ...$json, zalo_reply: msg } }];
